];

const initialCategories: Category[] = ['Blusas', 'Vestidos', 'Pantalones', 'Accesorios', 'Chaquetas', 'Bolsos'];

// --- Helper Functions ---
const useBrowserStorage = <T,>(key: string, initialValue: T): [T, React.Dispatch<React.SetStateAction<T>>] => {
  const [storedValue, setStoredValue] = useState<T>(() => {
    try {
      const item = window.localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch (error) {
      console.error(`Error reading from localStorage for key "${key}":`, error);
      return initialValue;
    }
  });

  const setValue: React.Dispatch<React.SetStateAction<T>> = (value) => {
    try {
      const valueToStore = value instanceof Function ? value(storedValue) : value;
      setStoredValue(valueToStore);
      try {
        window.localStorage.setItem(key, JSON.stringify(valueToStore));
      } catch (error) {
        console.warn(`LocalStorage quota exceeded or error saving key "${key}".`);
      }
    } catch (error) {
      console.error(`Error in useBrowserStorage setValue for key "${key}":`, error);
    }
  };
  return [storedValue, setValue];
};

const useFirestoreDocSync = <T extends object>(collectionName: string, docId: string, initialValue: T): [T, (value: T) => void, boolean] => {
    const [data, setData] = useState<T>(initialValue);
    const [isLoading, setIsLoading] = useState(true);
    const docRef = useMemo(() => doc(db, collectionName, docId), [collectionName, docId]);

    useEffect(() => {
        const unsubscribe = onSnapshot(docRef,
            (docSnap) => {
                if (docSnap.exists()) {
                    setData(docSnap.data() as T);
                } else {
                    setDoc(docRef, initialValue).catch(error => console.error(`Firestore error for ${collectionName}/${docId}:`, error));
                }
                setIsLoading(false);
            },
            (error) => {
                console.error(`Firestore error for ${collectionName}/${docId}:`, error);
                setIsLoading(false);
            }
        );
        return () => unsubscribe();
    }, [docRef]);

    const setValue = useCallback((value: T) => {
        try {
            setDoc(docRef, value, { merge: true });
        } catch (error) {
            console.error(`Firestore setDoc error for ${collectionName}/${docId}:`, error);
        }
    }, [docRef]);

    return [data, setValue, isLoading];
};

const useFirestoreCollectionSync = <T extends {docId: string}>(collectionName: string): [T[], boolean] => {
    const [data, setData] = useState<T[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const collectionRef = useMemo(() => collection(db, collectionName), [collectionName]);

    useEffect(() => {
        const unsubscribe = onSnapshot(collectionRef,
            (querySnapshot) => {
                const items = querySnapshot.docs.map(doc => ({ ...doc.data(), docId: doc.id } as T));
                setData(items);
                setIsLoading(false);
            },
            (error) => {
                console.error(`Firestore error for collection ${collectionName}:`, error);
                setIsLoading(false);
            }
        );
        return () => unsubscribe();
    }, [collectionRef]);

    return [data, isLoading];
};

const uploadImageToStorage = async (file: File): Promise<string> => {
    const fileName = `images/${Date.now()}-${file.name}`;
    const storageRef = ref(storage, fileName);
    await uploadBytes(storageRef, file);
    return await getDownloadURL(storageRef);
};

const App: React.FC = () => {
    // Global State
    const [config, setConfig, isConfigLoading] = useFirestoreDocSync<StoreConfig>('store', 'config', initialConfig);
    const [{ list: banners }, setBannersDoc, areBannersLoading] = useFirestoreDocSync<{list: Banner[]}>('store', 'banners', { list: initialBanners });
    const [{ list: categories }, setCategoriesDoc, areCategoriesLoading] = useFirestoreDocSync<{list: Category[]}>('store', 'categories', { list: initialCategories });
    const [rawInventoryProducts, areProductsLoading] = useFirestoreCollectionSync<any>('inventory');
    const [orders, areOrdersLoading] = useFirestoreCollectionSync<Order>('orders');
    const [users, areUsersLoading] = useFirestoreCollectionSync<User>('users');
    const [cart, setCart] = useBrowserStorage<CartItem[]>('storeCart', []);

    // Auth State
    const [currentUser, setCurrentUser] = useState<FirebaseUser | null>(null);
    const [userData, setUserData] = useState<User | null>(null);
    const [isAuthLoading, setAuthLoading] = useState(true);

    // UI State
    const [isMobileMenuOpen, setMobileMenuOpen] = useState(false);
    const [isCartOpen, setCartOpen] = useState(false);
    const [isAdminOpen, setAdminOpen] = useState(false);
    const [isSearchModalOpen, setSearchModalOpen] = useState(false);
    const [isInvoiceModalOpen, setInvoiceModalOpen] = useState(false);
    const [isAddUserModalOpen, setAddUserModalOpen] = useState(false);
    const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
    const [productToEdit, setProductToEdit] = useState<Product | null>(null);
    const [toasts, setToasts] = useState<ToastMessage[]>([]);
    const [isProductDetailFromCart, setProductDetailFromCart] = useState(false);

    // Search & Filter State
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedCategory, setSelectedCategory] = useState<Category | 'All' | 'On Sale'>('All');
    const [inlineSearchTerm, setInlineSearchTerm] = useState('');

    // Admin State
    const [editMode, setEditMode] = useState(false);

    const isAppLoading = isConfigLoading || areBannersLoading || areProductsLoading || areCategoriesLoading || areOrdersLoading || isAuthLoading || areUsersLoading;

    // --- PRODUCT MAPPING & FILTERING (New Requirement: Stock > 0) ---
    const products = useMemo(() => {
        return (rawInventoryProducts || []).map(p => ({
            ...p,
            id: p.docId, // Use document ID as main ID for the app
            name: p.name || 'Sin nombre',
            description: p.description || '',
            price: Number(p.price) || 0,
            category: p.categoryId || p.category || 'Varios',
            imageUrl: p.imageUrl || 'https://via.placeholder.com/300x400?text=Sin+Imagen',
            available: (Number(p.stock) > 0 && !p.isDisabled),
            variants: p.variants || { hasSizes: false, sizes: {}, hasColors: false, colors: {} }
        } as Product));
    }, [rawInventoryProducts]);

    useEffect(() => { setInlineSearchTerm(searchTerm); }, [searchTerm]);

    // --- ROUTING LOGIC ---
    const [currentPath, setCurrentPath] = useState(window.location.hash);
    useEffect(() => {
        const onHashChange = () => setCurrentPath(window.location.hash);
        window.addEventListener('hashchange', onHashChange);
        return () => window.removeEventListener('hashchange', onHashChange);
    }, []);

    useEffect(() => {
        const route = currentPath.replace(/^#/, '');
        const productMatch = route.match(/^\/product\/([^/]+)/);
        if (productMatch) {
            const product = products.find(p => p.id === productMatch[1]);
            if (product) setSelectedProduct(product);
            else if (!areProductsLoading) window.location.hash = '/';
        } else setSelectedProduct(null);
        setAdminOpen(route === '/admin');
        setCartOpen(route === '/cart');
        setInvoiceModalOpen(route === '/checkout');
        if (!productMatch) setProductDetailFromCart(false);
    }, [currentPath, products, areProductsLoading]);

    const navigate = (path: string) => { window.location.hash = path; };
    const closeModal = () => navigate('/');
    const handleOpenProductDetails = (product: Product) => navigate(`/product/${product.id}`);
    const handleOpenCart = () => navigate('/cart');
    const handleOpenAdmin = () => navigate('/admin');

    // --- AUTH EFFECT ---
    useEffect(() => {
        const unsubscribe = onAuthStateChanged(auth, async (user) => {
            setCurrentUser(user);
            if (user) {
                const userDocSnap = await getDoc(doc(db, 'users', user.uid));
                if (userDocSnap.exists()) setUserData({ ...userDocSnap.data(), docId: userDocSnap.id } as User);
                else setUserData(null);
            } else setUserData(null);
            setAuthLoading(false);
        });
        return () => unsubscribe();
    }, []);

    // --- UTILS ---
    const showToast = (message: string, type: 'success' | 'error' = 'success') => {
        const id = Date.now();
        setToasts(prev => [...prev, { id, message, type }]);
        setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3000);
    };

    const formatCurrency = (amount: number) => new Intl.NumberFormat('es-CO', { style: 'currency', currency: 'COP', minimumFractionDigits: 0 }).format(amount);
    const handleLogout = async () => { try { await signOut(auth); showToast("Sesión cerrada."); closeModal(); } catch (e) { showToast("Error al salir.", "error"); } };

    // --- DERIVED STATE ---
    const cartItemCount = useMemo(() => cart.reduce((sum, item) => sum + item.quantity, 0), [cart]);
    const cartSubtotal = useMemo(() => cart.reduce((sum, item) => sum + item.price * item.quantity, 0), [cart]);

    // Filter by stock and visibility (New Requirement: Only show products with units)
    const filteredProducts = useMemo(() => {
        return products.filter(product => {
            if (!product.available) return false; // This filters out stock <= 0 or disabled
            let matchesCategory = true;
            if (selectedCategory === 'On Sale') matchesCategory = !!(product.discountPercentage && product.discountPercentage > 0);
            else if (selectedCategory !== 'All') matchesCategory = product.category === selectedCategory;
            const searchTerms = searchTerm.toLowerCase().split(/\s+/).filter(Boolean);
            const matchesSearch = searchTerms.every(term => `${product.name} ${product.description} ${product.category}`.toLowerCase().includes(term));
            return matchesCategory && matchesSearch;
        });
    }, [products, selectedCategory, searchTerm]);

    const newArrivals = useMemo(() => [...products].filter(p => p.available).sort((a,b) => b.id.localeCompare(a.id)).slice(0, 6), [products]);
    const bestSellers = useMemo(() => [...products].filter(p => p.available).sort(() => Math.random() - 0.5).slice(0, 8), [products]);

    // --- HANDLERS ---
    const handleAddToCart = (product: Product, quantity: number, size?: string, color?: string) => {
        const cartItemId = `${product.id}${size ? `-${size}` : ''}${color ? `-${color}` : ''}`;
        const existingItem = cart.find(item => item.id === cartItemId);
        const price = product.discountPercentage ? product.price * (1 - product.discountPercentage / 100) : product.price;
        if (existingItem) setCart(cart.map(item => item.id === cartItemId ? { ...item, quantity: item.quantity + quantity } : item));
        else setCart([...cart, { id: cartItemId, productId: product.id, name: product.name, price, quantity, imageUrl: (color && product.variants?.colors?.[color]?.imageUrl) || product.imageUrl, size, color }]);
        showToast(`${product.name} agregado!`);
        if (isProductDetailFromCart) navigate('/cart'); else closeModal();
    };

    const handleQuickAddToCart = (product: Product) => {
      const hasVariants = !!(product.variants?.hasSizes || product.variants?.hasColors);
      if (hasVariants) { setProductDetailFromCart(false); handleOpenProductDetails(product); }
      else handleAddToCart(product, 1);
    };

    const handleUpdateCartQuantity = (id: string, qty: number) => {
        if (qty <= 0) setCart(cart.filter(item => item.id !== id));
        else setCart(cart.map(item => item.id === id ? { ...item, quantity: qty } : item));
    };

    const handleNewOrder = async (orderData: Omit<Order, 'docId' | 'orderNumber' | 'status' | 'date'>) => {
        try {
            const orderCounterRef = doc(db, 'store', 'orderCounter');
            const newOrderNumber = await runTransaction(db, async (transaction) => {
                const counterDoc = await transaction.get(orderCounterRef);
                let next = (counterDoc.data()?.currentNumber || 1000) + 1;
                transaction.set(orderCounterRef, { currentNumber: next }, { merge: true });
                return next;
            });
            const orderNumber = `BMB-${newOrderNumber}`;
            const newOrder = { ...orderData, orderNumber, status: 'Pendiente' as const, date: new Date().toISOString() };
            const waMsg = `¡Hola! Pedido ${orderNumber}:\n${newOrder.items.map(i => `- ${i.quantity}x ${i.name}`).join('\n')}\nTotal: ${formatCurrency(newOrder.total)}`;
            window.open(`https://wa.me/${config.social.whatsapp}?text=${encodeURIComponent(waMsg)}`, '_blank');
            await addDoc(collection(db, 'orders'), newOrder);
            setCart([]); navigate('/'); showToast("Pedido enviado!");
        } catch (e) { showToast("Error al procesar pedido.", "error"); }
    };

    // --- ADMIN CRUD (Updated for Inventory Collection) ---
    const handleAddProduct = async (p: Product) => {
        const { id, ...data } = p;
        await addDoc(collection(db, 'inventory'), { ...data, stock: 1 }); // Default stock 1 to make it visible
        showToast("Producto agregado.");
    };
    const handleUpdateProduct = async (p: Product) => {
        const { id, ...data } = p;
        await setDoc(doc(db, 'inventory', id), data, { merge: true });
        showToast("Producto actualizado.");
    };
    const handleDeleteProduct = async (id: string) => {
        if (window.confirm("¿Eliminar producto?")) {
            await deleteDoc(doc(db, 'inventory', id));
            showToast("Producto eliminado.", "error");
        }
    };

    if (isAppLoading) return (
        <div className="flex items-center justify-center h-screen bg-background">
            <svg className="animate-spin h-10 w-10 text-primary" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
            </svg>
        </div>
    );

    return (
        <div className="bg-background min-h-screen">
            <div className="fixed top-5 right-5 z-[100] space-y-2">
                {toasts.map(t => <div key={t.id} className={`px-4 py-2 rounded-md shadow-lg text-white ${t.type === 'success' ? 'bg-primary' : 'bg-red-500'}`}>{t.message}</div>)}
            </div>
            <Header logoUrl={config.logoUrl} cartItemCount={cartItemCount} onCartClick={handleOpenCart} isMobileMenuOpen={isMobileMenuOpen} setMobileMenuOpen={setMobileMenuOpen} categories={categories} onSelectCategory={(e, c) => { e.preventDefault(); setSelectedCategory(c); setMobileMenuOpen(false); }} selectedCategory={selectedCategory} currentUser={currentUser} onAdminClick={handleOpenAdmin} onSearchClick={() => setSearchModalOpen(true)} />
            <CategoryNav categories={categories} selectedCategory={selectedCategory} onSelectCategory={setSelectedCategory} />
            <main className="pt-12">
                <BannerCarousel banners={banners} onNavigateToCategory={setSelectedCategory} />
                {selectedCategory === 'All' && (
                    <>
                        <ProductCarousel title="Lo Nuevo" products={newArrivals} />
                        <ProductCarousel title="Más Vendidos" products={bestSellers} />
                    </>
                )}
                <section id="productos" className="py-12 bg-surface">
                    <div className="max-w-7xl 2xl:max-w-screen-2xl mx-auto px-4">
                        <h2 className="text-3xl font-serif text-center mb-8">{selectedCategory === 'All' ? 'Catálogo Completo' : selectedCategory}</h2>
                        <div className="flex justify-center mb-8">
                            <div className="relative w-full md:w-1/2">
                                <input type="text" placeholder="Buscar productos..." value={inlineSearchTerm} onChange={e => { setInlineSearchTerm(e.target.value); if(!e.target.value) setSearchTerm(''); }} onKeyDown={e => e.key === 'Enter' && setSearchTerm(inlineSearchTerm)} className="w-full bg-white border rounded-full pl-10 pr-4 py-2 focus:ring-2 focus:ring-primary" />
                                <SearchIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
                            </div>
                        </div>
                        <div className="grid grid-cols-2 gap-4 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6">
                            {filteredProducts.map(p => (
                                <div key={p.id} className="group bg-white rounded-lg shadow-md overflow-hidden cursor-pointer" onClick={() => handleOpenProductDetails(p)}>
                                    <div className="relative aspect-[4/5] overflow-hidden">
                                        <img src={p.imageUrl} className="w-full h-full object-cover group-hover:scale-105 transition-transform" />
                                        <button onClick={e => { e.stopPropagation(); handleQuickAddToCart(p); }} className="absolute bottom-2 right-2 bg-white/80 p-2 rounded-full scale-0 group-hover:scale-100 transition-all shadow-md"><PlusIcon className="w-5 h-5 text-primary" /></button>
                                    </div>
                                    <div className="p-4"><h3 className="font-semibold text-sm truncate">{p.name}</h3><p className="text-primary font-bold">{formatCurrency(p.price)}</p></div>
                                </div>
                            ))}
                        </div>
                    </div>
                </section>
            </main>
            <Footer contact={config.contact} social={config.social} onAdminClick={handleOpenAdmin} />
            {isCartOpen && <CartPanel onClose={closeModal} cart={cart} subtotal={cartSubtotal} onUpdateQuantity={handleUpdateCartQuantity} onRemoveItem={id => setCart(cart.filter(i => i.id !== id))} onCheckout={() => navigate('/checkout')} formatCurrency={formatCurrency} suggestedProducts={bestSellers} onAddSuggestedProduct={p => handleAddToCart(p, 1)} onClearCart={() => setCart([])} onContinueShopping={closeModal} />}
            {isAdminOpen && (currentUser ? <AdminPanel user={userData!} onClose={closeModal} editMode={editMode} setEditMode={setEditMode} store={{ config, banners, products, categories, orders, users }} onUpdateConfig={setConfig} onSaveBanners={l => setBannersDoc({list: l})} onSaveCategories={l => setCategoriesDoc({list: l})} onAddProduct={handleAddProduct} onUpdateProduct={handleUpdateProduct} onDeleteProduct={handleDeleteProduct} formatCurrency={formatCurrency} productToEdit={productToEdit} onDeleteOrder={id => deleteDoc(doc(db, 'orders', id))} onUpdateOrder={(id, d) => updateDoc(doc(db, 'orders', id), d)} onLogout={handleLogout} onAddUser={() => setAddUserModalOpen(true)} onUpdateUserRole={(id, r) => updateDoc(doc(db, 'users', id), {role: r})} onDeleteUser={id => deleteDoc(doc(db, 'users', id))} /> : <LoginPage onClose={closeModal} showToast={showToast} />)}
            {selectedProduct && <ProductDetailModal product={selectedProduct} onClose={closeModal} onAddToCart={handleAddToCart} formatCurrency={formatCurrency} showToast={showToast} />}
            {isInvoiceModalOpen && <InvoiceModal onClose={() => navigate('/cart')} cart={cart} subtotal={cartSubtotal} onSubmitOrder={handleNewOrder} config={config} formatCurrency={formatCurrency} />}
            <a href={`https://wa.me/${config.social.whatsapp}`} target="_blank" className="fixed bottom-5 right-5 bg-primary text-white p-4 rounded-full shadow-lg"><WhatsAppIcon className="w-8 h-8" /></a>
        </div>
    );
};

// --- Reused components remain identical to previous implementation but optimized ---
const Header = ({ logoUrl, cartItemCount, onCartClick, isMobileMenuOpen, setMobileMenuOpen, categories, onSelectCategory, selectedCategory, currentUser, onAdminClick, onSearchClick }: any) => (
