        return (rawInventory || []).map(p => {
            const categoryObj = categoriesData.find(c => c.docId === p.categoryId);
            return {
                ...p,
                id: p.docId,
                name: p.name || 'Sin nombre',
                price: Number(p.price) || 0,
                category: categoryObj ? categoryObj.name : 'Otros',
                categoryId: p.categoryId,
                imageUrl: p.imageUrl || 'https://via.placeholder.com/300x400',
                available: (Number(p.stock) > 0 && !p.isDisabled),
                variants: p.variants || { hasSizes: false, sizes: {}, hasColors: false, colors: {} }
            } as Product;
        });
    }, [rawInventory, categoriesData]);

    // --- Filtros ---
    const filteredProducts = useMemo(() => {
        return products.filter(p => {
            if (!p.available) return false;
            const matchesCategory = selectedCategoryId === 'All' || p.categoryId === selectedCategoryId;
            const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase());
            return matchesCategory && matchesSearch;
        });
    }, [products, selectedCategoryId, searchTerm]);

    const categoriesList = useMemo(() => categoriesData.map(c => ({ id: c.docId, name: c.name })), [categoriesData]);

    useEffect(() => {
        const unsubscribe = onAuthStateChanged(auth, (user) => setCurrentUser(user));
        return () => unsubscribe();
