        if (existing) setCart(cart.map(i => i.id === cartItemId ? { ...i, quantity: i.quantity + quantity } : i));
        else setCart([...cart, { id: cartItemId, productId: product.id, name: product.name, price: product.price, quantity, imageUrl: product.imageUrl, size, color }]);
