          ))}
          {cart.length === 0 && (
            <div className="text-center py-32 space-y-4">
              <p className="text-gray-300 font-serif text-xl italic">"Tu carrito espera por tu estilo"</p>
              <button onClick={onClose} className="text-primary font-bold uppercase tracking-widest text-xs border-b-2 border-primary">Ir de compras</button>
            </div>
          )}
        </div>
        <div className="p-8 border-t bg-gray-50">
          <div className="flex justify-between items-center mb-8">
            <span className="font-bold text-gray-500 uppercase tracking-widest text-xs">Total del pedido</span>
            <span className="text-3xl font-black text-primary">{formatCurrency(total)}</span>
          </div>
          <button className="w-full bg-black text-white py-6 rounded-2xl font-black uppercase tracking-widest text-xs shadow-2xl hover:bg-gray-900 transition-all active:scale-95">Finalizar Compra</button>
        </div>
      </div>
    </div>
  );
};

